import React, { useState } from "react";
import { Form, Input, Slider } from "antd";

const { TextArea } = Input;

function CeasarTab(props) {
    const { getFieldDecorator } = props.form;
    const [key, setKey] = useState(1);
    const [inputText, setInputText] = useState("");
    const [outputText, setOutputText] = useState("");

    function getKeyMarks() {
        const marks = {};
        for(let i = 0; i <= 26; i++) {
            marks[i] = String.fromCharCode(96 + i).toUpperCase(); 
        }
        return marks;
    }
 
    function handleSliderChange(value) {
        console.log(value);
        setKey(value);
        updateOutput(inputText);
    }

    function handleInputChange(e) {
        setInputText(e.target.value);
        updateOutput(e.target.value);
    }

    function updateOutput(inputValue) {
        if (!inputValue || inputValue.length < 1) {
            setOutputText("");
            return;
        }

        let outputValue = "";
        for (let i = 0; i < inputValue.length; i++) {
            outputValue += String.fromCharCode((inputValue.charCodeAt(i) + key));
        }
        setOutputText(outputValue);
    }

    return (
        <div>
            <Form>
                <Form.Item label="Key">
                    {getFieldDecorator("slider")(
                        <Slider min={1} max={26} onChange={handleSliderChange} marks={getKeyMarks()}/>
                    )}
                </Form.Item>
                <Form.Item label="Input">
                    <TextArea onChange={handleInputChange} />
                </Form.Item>
                <Form.Item label="Output">
                    <TextArea value={outputText} disabled />
                </Form.Item>
            </Form>
        </div>
    );
}

const ceasarTab = Form.create({name: "ceasar-tab"})(CeasarTab);
export default ceasarTab;